/* ========================================
   Tarot Mini App — Base Styles
   ======================================== */

:root {
  --bg-color: #1a0b2e;
  --bg-gradient: linear-gradient(135deg, #1a0b2e 0%, #2d1f4e 50%, #1a0b2e 100%);
  --gold: #d4af37;
  --gold-light: #f4d06f;
  --text-primary: #f5f5f5;
  --text-secondary: rgba(245, 245, 245, 0.7);
  --card-width: 100px;
  --card-height: 160px;
  --card-radius: 8px;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Georgia, serif;
  background: var(--bg-gradient);
  color: var(--text-primary);
}

#app {
  width: 100%;
  height: 100%;
  position: relative;
  overflow: hidden;
}

/* Canvas фоны */
#stars-canvas,
#particles-canvas {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

#particles-canvas {
  z-index: 100;
}

/* ========================================
   Экраны
   ======================================== */

.screen {
  display: none;
  width: 100%;
  height: 100%;
  padding: 20px;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.screen.active {
  display: flex;
  opacity: 1;
}

/* ========================================
   Типографика
   ======================================== */

.title {
  font-family: 'Cormorant Garamond', serif;
  font-size: 48px;
  font-weight: 700;
  color: var(--gold);
  text-shadow: 0 0 20px rgba(212, 175, 55, 0.5);
  margin-bottom: 10px;
  letter-spacing: 4px;
}

/* Golden Tarot - магический древний шрифт */
.golden-title {
  font-family: 'Cinzel', 'Cormorant Garamond', serif;
  font-size: 56px;
  font-weight: 700;
  background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 50%, var(--gold) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: 0 0 30px rgba(212, 175, 55, 0.7), 0 0 60px rgba(212, 175, 55, 0.4);
  letter-spacing: 6px;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}

.shuffle-hint {
  color: var(--text-secondary);
  font-size: 14px;
  margin-bottom: 20px;
  text-align: center;
  font-style: italic;
}

.shuffle-timer {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-family: 'Cormorant Garamond', serif;
  font-size: 72px;
  font-weight: 700;
  color: var(--gold);
  text-shadow: 0 0 30px rgba(212, 175, 55, 0.8);
  z-index: 100;
  animation: timerPulse 1s ease-in-out infinite;
}

@keyframes timerPulse {
  0%, 100% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
  50% { opacity: 0.7; transform: translate(-50%, -50%) scale(1.1); }
}

.screen-title {
  font-family: 'Cormorant Garamond', serif;
  font-size: 32px;
  font-weight: 600;
  color: var(--gold);
  margin-bottom: 24px;
  text-align: center;
}

.hint {
  color: var(--text-secondary);
  font-size: 14px;
  margin-top: 20px;
  text-align: center;
}

/* ========================================
   Главный экран: колода
   ======================================== */

#screen-main {
  position: relative;
}

#screen-situation {
  padding-bottom: 80px;
  overflow-y: auto;
}

.settings-btn {
  position: absolute;
  top: 20px;
  right: 20px;
  background: none;
  border: none;
  color: var(--gold);
  cursor: pointer;
  padding: 8px;
  opacity: 0.7;
  transition: opacity 0.2s, transform 0.2s;
}

.settings-btn:hover {
  opacity: 1;
  transform: rotate(30deg);
}

.deck-container {
  width: calc(var(--card-width) * 2.5);
  height: calc(var(--card-height) * 2.5);
  position: relative;
  cursor: pointer;
  transition: transform 0.3s ease;
  background-image: url('../assets/card-backs/back.webp');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  border-radius: calc(var(--card-radius) * 2.5);
  box-shadow: 0 8px 40px rgba(0, 0, 0, 0.6), 0 0 30px rgba(212, 175, 55, 0.3);
}

.deck-container:hover {
  transform: scale(1.03);
  box-shadow: 0 12px 50px rgba(0, 0, 0, 0.7), 0 0 40px rgba(212, 175, 55, 0.5);
}

.deck-container.shuffling {
  animation: shuffle-shake 0.5s ease-in-out;
}

@keyframes shuffle-shake {
  0%, 100% { transform: translateX(0) rotate(0); }
  25% { transform: translateX(-15px) rotate(-3deg); }
  50% { transform: translateX(15px) rotate(3deg); }
  75% { transform: translateX(-15px) rotate(-3deg); }
}

/* ========================================
   Экран выбора расклада
   ======================================== */

.spread-options {
  display: flex;
  flex-direction: column;
  gap: 16px;
  width: 100%;
  max-width: 300px;
}

.spread-btn {
  background: linear-gradient(135deg, rgba(212, 175, 55, 0.1) 0%, rgba(212, 175, 55, 0.2) 100%);
  border: 1px solid var(--gold);
  border-radius: 12px;
  padding: 20px;
  color: var(--text-primary);
  cursor: pointer;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  transition: all 0.3s ease;
}

.spread-btn:hover {
  background: linear-gradient(135deg, rgba(212, 175, 55, 0.2) 0%, rgba(212, 175, 55, 0.3) 100%);
  transform: translateY(-2px);
  box-shadow: 0 4px 20px rgba(212, 175, 55, 0.3);
}

.spread-btn:active {
  transform: translateY(0);
}

.spread-icon {
  font-size: 36px;
}

.spread-name {
  font-family: 'Cormorant Garamond', serif;
  font-size: 20px;
