}

.spread-desc {
  font-size: 14px;
  color: var(--text-secondary);
}

/* ========================================
   Кнопки навигации
   ======================================== */

.back-btn {
  margin-top: 24px;
  background: none;
  border: 1px solid var(--text-secondary);
  border-radius: 8px;
  padding: 10px 24px;
  color: var(--text-secondary);
  font-size: 14px;
  cursor: pointer;
  transition: all 0.2s ease;
