/* ========================================
   Контейнеры карт
   ======================================== */

.cards-container {
  display: flex;
  justify-content: center;
  gap: 12px;
  flex-wrap: wrap;
  margin: 20px 0;
  min-height: var(--card-height);
}

/* ========================================
   Расклад на ситуацию — схема «Путь»
   ======================================== */

.situation-layout {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  margin: 10px auto;
  padding: 10px;
  max-width: 450px;
}

/* Ряд с картами */
.situation-cards-row {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 10px;
  width: 100%;
}

/* Центральная карта в ряду */
.situation-cards-row .situation-card-center {
  margin: 0 8px;
}

.situation-card-slot {
  width: var(--card-width);
  height: calc(var(--card-height) + 20px);
  position: relative;
