    const startTime = new Date(session.start_time).getTime();
    const elapsed = (Date.now() - startTime) / 1000;
    const timeLeft = Math.max(0, session.duration_seconds - elapsed);

    socket.emit('time-left', { timeLeft, expired: timeLeft <= 0 });
  });

