  margin-bottom: 4px;
}

.tarologist-description {
  font-size: 12px;
  color: var(--text-secondary);
  line-height: 1.4;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: 8px;
}

.tarologist-meta {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.tarologist-rating {
  display: flex;
  align-items: center;
  gap: 2px;
  font-size: 14px;
}

.tarologist-stars {
  color: var(--gold);
  text-shadow: 0 0 8px rgba(212, 175, 55, 0.6);
}

.tarologist-rating-value {
  color: var(--text-secondary);
  font-size: 11px;
}

.tarologist-price {
