}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.tarologist-loading p {
  color: var(--text-secondary);
  font-size: 14px;
}

/* ========================================
   МОДАЛЬНОЕ ОКНО ОПЛАТЫ
