  font-size: 16px;
  font-weight: 600;
  color: var(--gold);
}

.chat-status {
  font-size: 11px;
  color: var(--text-secondary);
}

.chat-timer {
  display: flex;
  align-items: center;
  gap: 6px;
  background: rgba(212, 175, 55, 0.1);
  padding: 6px 12px;
