  border: 1px solid rgba(212, 175, 55, 0.3);
}

.timer-icon {
  font-size: 14px;
}

.timer-value {
  font-family: 'Cormorant Garamond', serif;
  font-size: 16px;
  font-weight: 600;
  color: var(--gold);
  min-width: 50px;
  text-align: right;
}

.chat-timer.urgent {
  animation: timerUrgent 1s ease-in-out infinite;
}

@keyframes timerUrgent {
  0%, 100% { border-color: rgba(212, 175, 55, 0.3); }
  50% { border-color: rgba(239, 68, 68, 0.6); }
}

.chat-messages {
  flex: 1;
  width: 100%;
  padding: 16px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.chat-message {
  max-width: 80%;
  padding: 10px 14px;
  border-radius: 16px;
  font-size: 14px;
  line-height: 1.4;
  word-wrap: break-word;
  animation: messageSlide 0.3s ease;
}

@keyframes messageSlide {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.chat-message.client {
  align-self: flex-end;
  background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
  color: #1a0b2e;
  border-bottom-right-radius: 4px;
}

.chat-message.tarologist {
  align-self: flex-start;
  background: rgba(255, 255, 255, 0.1);
  color: var(--text-primary);
  border-bottom-left-radius: 4px;
}

.chat-message-time {
  font-size: 10px;
  opacity: 0.7;
  margin-top: 4px;
  text-align: right;
}

.chat-input-container {
  width: 100%;
  padding: 16px;
  background: linear-gradient(135deg, rgba(26, 11, 46, 0.95) 0%, rgba(45, 31, 78, 0.95) 100%);
  border-top: 1px solid rgba(212, 175, 55, 0.2);
  display: flex;
  gap: 12px;
  align-items: center;
}

.chat-input {
  flex: 1;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 24px;
  padding: 12px 16px;
  font-size: 14px;
  color: var(--text-primary);
  outline: none;
  transition: all 0.2s ease;
}

.chat-input:focus {
  border-color: rgba(212, 175, 55, 0.4);
  background: rgba(255, 255, 255, 0.08);
}

.chat-input::placeholder {
  color: var(--text-secondary);
}

.chat-send-btn {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
  border: none;
  color: #1a0b2e;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s ease;
  flex-shrink: 0;
}

.chat-send-btn:hover {
  transform: scale(1.1);
  box-shadow: 0 4px 16px rgba(212, 175, 55, 0.4);
}

.chat-send-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
}

.chat-timeout-message {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(26, 11, 46, 0.98);
  border: 2px solid rgba(212, 175, 55, 0.4);
  border-radius: 16px;
  padding: 24px 32px;
  text-align: center;
  z-index: 100;
}

.chat-timeout-message p:first-child {
  font-family: 'Cormorant Garamond', serif;
  font-size: 20px;
  font-weight: 600;
  color: var(--gold);
  margin-bottom: 8px;
}

.timeout-subtext {
  color: var(--text-secondary);
  font-size: 13px;
  font-style: italic;
}

/* ========================================
   ЭКРАН ОЦЕНКИ
   ======================================== */

.rating-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 20px;
  padding: 20px;
  max-width: 400px;
}

.rating-icon {
  font-size: 64px;
  filter: drop-shadow(0 0 20px rgba(212, 175, 55, 0.5));
}

.rating-title {
  font-family: 'Cormorant Garamond', serif;
  font-size: 28px;
  font-weight: 600;
  color: var(--gold);
  text-align: center;
}

.rating-subtitle {
  color: var(--text-secondary);
  font-size: 14px;
  text-align: center;
}

.stars-rating {
  display: flex;
  gap: 8px;
  margin: 16px 0;
}

.star-btn {
  background: none;
  border: none;
  font-size: 48px;
  color: rgba(212, 175, 55, 0.3);
  cursor: pointer;
  transition: all 0.2s ease;
  padding: 0;
  line-height: 1;
