.submit-rating-btn {
  background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
  border: none;
  border-radius: 12px;
  padding: 14px 40px;
  color: #1a0b2e;
  font-family: 'Cormorant Garamond', serif;
  font-size: 16px;
  font-weight: 600;
