      themeParams: {},
      expand: () => {},
      ready: () => {},
      showAlert: (msg) => alert(msg),
      showConfirm: (msg, callback) => callback(confirm(msg)),
      HapticFeedback: {
        impactOccurred: () => {},
        notificationOccurred: () => {}
      },
      Clipboard: {
        writeText: (text, callback) => {
          navigator.clipboard.writeText(text).then(() => callback(true));
        }
      },
