  box-shadow: 0 6px 20px rgba(212, 175, 55, 0.3);
}

/* Списки */
.tarologists-admin-list,
.transactions-list,
.payouts-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  width: 100%;
  max-width: 500px;
  margin-bottom: 20px;
}

/* Карточка таролога в админке */
.tarologist-admin-card {
  background: linear-gradient(135deg, rgba(212, 175, 55, 0.1) 0%, rgba(212, 175, 55, 0.15) 100%);
  border: 1px solid rgba(212, 175, 55, 0.3);
  border-radius: 12px;
  padding: 16px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  cursor: pointer;
  transition: all 0.2s ease;
}

.tarologist-admin-card:hover {
  border-color: rgba(212, 175, 55, 0.5);
  background: linear-gradient(135deg, rgba(212, 175, 55, 0.15) 0%, rgba(212, 175, 55, 0.2) 100%);
  transform: translateY(-2px);
}

.tarologist-admin-info {
  flex: 1;
}

.tarologist-admin-name {
  font-family: 'Cormorant Garamond', serif;
  font-size: 18px;
  font-weight: 600;
  color: var(--gold);
  margin-bottom: 4px;
}

.tarologist-admin-meta {
  display: flex;
  gap: 12px;
  font-size: 12px;
  color: var(--text-secondary);
}

.tarologist-admin-balance {
  background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
  color: #1a0b2e;
  padding: 6px 12px;
  border-radius: 20px;
  font-size: 14px;
  font-weight: 700;
  white-space: nowrap;
}

/* Транзакции */
.transaction-item {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 10px;
  padding: 14px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.transaction-info {
  flex: 1;
}

.transaction-amount {
  font-family: 'Cormorant Garamond', serif;
  font-size: 18px;
  font-weight: 600;
  color: var(--gold);
  margin-bottom: 4px;
}

.transaction-details {
  font-size: 11px;
  color: var(--text-secondary);
}

.transaction-date {
  font-size: 10px;
  color: var(--text-secondary);
  opacity: 0.7;
}

/* Выплаты */
.payout-item {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(212, 175, 55, 0.2);
  border-radius: 10px;
  padding: 14px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.payout-info {
  flex: 1;
}

.payout-tarologist {
  font-family: 'Cormorant Garamond', serif;
  font-size: 16px;
  font-weight: 600;
  color: var(--gold);
  margin-bottom: 4px;
}

.payout-amount-display {
  font-size: 14px;
  color: var(--text-primary);
}

.payout-status {
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
}

.payout-status.pending {
  background: rgba(255, 150, 100, 0.2);
  color: #ff9664;
}

.payout-status.completed {
  background: rgba(100, 255, 150, 0.2);
  color: #64ff96;
}

/* Фильтры */
.filters {
  margin-bottom: 16px;
  width: 100%;
  max-width: 300px;
}

.filter-select {
  width: 100%;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(212, 175, 55, 0.3);
  border-radius: 8px;
  padding: 10px 14px;
  color: var(--text-primary);
  font-size: 14px;
  font-family: 'Cormorant Garamond', serif;
  cursor: pointer;
  outline: none;
}

.filter-select:focus {
  border-color: var(--gold);
}

/* Загрузка */
.loading {
  display: none;
  flex-direction: column;
  align-items: center;
  gap: 16px;
  padding: 40px;
}

.loading.active {
  display: flex;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 3px solid rgba(212, 175, 55, 0.2);
  border-top-color: var(--gold);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.loading p {
  color: var(--text-secondary);
  font-size: 14px;
}

/* Модальные окна */
.modal-tarologist,
.modal-confirm {
  max-width: 360px;
}

.tarologist-stats {
  margin: 20px 0;
}

.stat-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 0;
  border-bottom: 1px solid rgba(212, 175, 55, 0.2);
}

.stat-row:last-child {
  border-bottom: none;
}

.stat-row .stat-label {
  color: var(--text-secondary);
  font-size: 14px;
}

.stat-row .stat-value {
  font-size: 16px;
  color: var(--text-primary);
}

.stat-row .stat-value.stars {
  color: var(--gold);
  font-weight: 600;
}

/* Кнопки действий */
.modal-actions,
.confirm-actions {
  display: flex;
  gap: 12px;
  margin-top: 20px;
}

.action-btn {
  flex: 1;
  padding: 14px 20px;
  border-radius: 10px;
  font-size: 15px;
  font-weight: 600;
  font-family: 'Cormorant Garamond', serif;
  cursor: pointer;
  transition: all 0.2s ease;
  border: none;
}

.action-btn-primary {
  background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
  color: #1a0b2e;
}

.action-btn-primary:hover {
  transform: scale(1.05);
  box-shadow: 0 6px 20px rgba(212, 175, 55, 0.4);
}

.action-btn-secondary {
  background: rgba(255, 255, 255, 0.1);
  color: var(--text-secondary);
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.action-btn-secondary:hover {
  background: rgba(255, 255, 255, 0.15);
  color: var(--text-primary);
}

/* Подтверждение */
.confirm-text {
  color: var(--text-primary);
  font-size: 14px;
  line-height: 1.6;
  text-align: center;
  margin: 16px 0;
}

.confirm-text strong {
  color: var(--gold);
  font-weight: 600;
}

/* Пустое состояние */
.empty-state {
  text-align: center;
  padding: 40px 20px;
  color: var(--text-secondary);
}

.empty-state-icon {
  font-size: 48px;
  margin-bottom: 16px;
  opacity: 0.5;
}

.empty-state-text {
  font-size: 14px;
}

/* Адаптивность */
@media (max-width: 360px) {
  .admin-title {
    font-size: 28px;
  }

  .stats-grid {
    gap: 8px;
  }

  .stat-value {
    font-size: 24px;
  }

  .payout-amount {
    font-size: 36px;
  }
}

