/**
 * Database Module
 * SQLite база данных для Tarot Mini App
 */

import Database from 'better-sqlite3';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const db = new Database(join(__dirname, 'tarot.db'));

// Включаем внешние ключи
db.pragma('journal_mode = WAL');
db.pragma('foreign_keys = ON');

// Создаём таблицы
db.exec(`
  -- Таблица тарологов
  CREATE TABLE IF NOT EXISTS tarologists (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    photo_url TEXT,
    description TEXT,
    rating REAL DEFAULT 0,
    total_ratings INTEGER DEFAULT 0,
    sessions_completed INTEGER DEFAULT 0,
    telegram_id TEXT UNIQUE,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  -- Таблица пользователей
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    telegram_id TEXT UNIQUE NOT NULL,
    username TEXT,
    first_name TEXT,
    last_name TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  -- Таблица транзакций
  CREATE TABLE IF NOT EXISTS transactions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER NOT NULL,
    tarologist_id INTEGER NOT NULL,
    amount INTEGER NOT NULL,
    stars_amount INTEGER NOT NULL,
    developer_cut INTEGER DEFAULT 0,
    tarologist_cut INTEGER DEFAULT 0,
    status TEXT DEFAULT 'pending',
    telegram_payment_id TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (tarologist_id) REFERENCES tarologists(id)
  );

  -- Таблица сессий чата
  CREATE TABLE IF NOT EXISTS chat_sessions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER NOT NULL,
    tarologist_id INTEGER NOT NULL,
    start_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    end_time DATETIME,
    duration_seconds INTEGER DEFAULT 1500,
    active BOOLEAN DEFAULT 1,
    completed BOOLEAN DEFAULT 0,
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (tarologist_id) REFERENCES tarologists(id)
  );

  -- Таблица сообщений
  CREATE TABLE IF NOT EXISTS messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id INTEGER NOT NULL,
    sender_id INTEGER NOT NULL,
    sender_type TEXT NOT NULL,
    text TEXT NOT NULL,
    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (session_id) REFERENCES chat_sessions(id)
  );

  -- Индексы для производительности
  CREATE INDEX IF NOT EXISTS idx_transactions_user ON transactions(user_id);
  CREATE INDEX IF NOT EXISTS idx_transactions_tarologist ON transactions(tarologist_id);
  CREATE INDEX IF NOT EXISTS idx_chat_sessions_active ON chat_sessions(active);
  CREATE INDEX IF NOT EXISTS idx_messages_session ON messages(session_id);
`);

// ========================================
// Модели
// ========================================

export const Tarologist = {
  // Получить всех тарологов с рассчитанной ценой
  getAll() {
    const stmt = db.prepare(`
      SELECT
        id,
        name,
        photo_url,
        description,
        rating,
        total_ratings,
        sessions_completed,
        telegram_id
      FROM tarologists
      ORDER BY rating DESC, sessions_completed DESC
    `);

    const tarologists = stmt.all();

    return tarologists.map(t => ({
      ...t,
      level: Math.floor(t.sessions_completed / 10) + 1,
      price: calculatePrice(t.sessions_completed)
    }));
  },

  // Получить таролога по ID
  getById(id) {
    const stmt = db.prepare('SELECT * FROM tarologists WHERE id = ?');
    const tarologist = stmt.get(id);

    if (!tarologist) return null;

    return {
      ...tarologist,
      level: Math.floor(tarologist.sessions_completed / 10) + 1,
      price: calculatePrice(tarologist.sessions_completed)
    };
  },

  // Обновить рейтинг
  updateRating(id, rating) {
    const stmt = db.prepare(`
      UPDATE tarologists
      SET rating = ((rating * total_ratings) + ?) / (total_ratings + 1),
          total_ratings = total_ratings + 1
      WHERE id = ?
    `);
    return stmt.run(rating, id);
  },

  // Увеличить счётчик сессий
  incrementSessions(id) {
    const stmt = db.prepare(`
      UPDATE tarologists
      SET sessions_completed = sessions_completed + 1
      WHERE id = ?
    `);
    return stmt.run(id);
  },

  // Создать таролога (для инициализации)
  create(data) {
    const stmt = db.prepare(`
      INSERT INTO tarologists (name, photo_url, description, telegram_id)
      VALUES (?, ?, ?, ?)
    `);
    return stmt.run(data.name, data.photo_url, data.description, data.telegram_id);
  }
};

export const User = {
  // Найти или создать пользователя
  findOrCreate(telegramId, userData) {
    let user = this.getByTelegramId(telegramId);

    if (!user) {
      const stmt = db.prepare(`
        INSERT INTO users (telegram_id, username, first_name, last_name)
        VALUES (?, ?, ?, ?)
      `);
      const result = stmt.run(
        telegramId,
        userData.username || null,
        userData.first_name || null,
        userData.last_name || null
      );
      user = this.getById(result.lastInsertRowid);
    }

    return user;
  },

  getById(id) {
    const stmt = db.prepare('SELECT * FROM users WHERE id = ?');
    return stmt.get(id);
  },

  getByTelegramId(telegramId) {
    const stmt = db.prepare('SELECT * FROM users WHERE telegram_id = ?');
    return stmt.get(telegramId);
  }
};

export const Transaction = {
  create(data) {
    const stmt = db.prepare(`
      INSERT INTO transactions (user_id, tarologist_id, amount, stars_amount, developer_cut, tarologist_cut, status)
      VALUES (?, ?, ?, ?, ?, ?, ?)
    `);
    const result = stmt.run(
      data.userId,
      data.tarologistId,
      data.amount,
      data.starsAmount,
      data.developerCut,
      data.tarologistCut,
      data.status || 'pending'
    );
    return this.getById(result.lastInsertRowid);
  },

  getById(id) {
    const stmt = db.prepare(`
      SELECT t.*, u.telegram_id as user_telegram_id, tar.name as tarologist_name
      FROM transactions t
      JOIN users u ON t.user_id = u.id
      JOIN tarologists tar ON t.tarologist_id = tar.id
      WHERE t.id = ?
    `);
    return stmt.get(id);
  },

  updateStatus(id, status, telegramPaymentId = null) {
    const stmt = db.prepare(`
      UPDATE transactions
      SET status = ?, telegram_payment_id = ?
      WHERE id = ?
    `);
    return stmt.run(status, telegramPaymentId, id);
  }
};

export const ChatSession = {
  create(data) {
    const stmt = db.prepare(`
      INSERT INTO chat_sessions (user_id, tarologist_id, duration_seconds, active)
      VALUES (?, ?, ?, 1)
    `);
    const result = stmt.run(data.userId, data.tarologistId, data.durationSeconds || 1500);
    return this.getById(result.lastInsertRowid);
  },

  getById(id) {
    const stmt = db.prepare(`
      SELECT cs.*, u.telegram_id as user_telegram_id, tar.telegram_id as tarologist_telegram_id
      FROM chat_sessions cs
      JOIN users u ON cs.user_id = u.id
      JOIN tarologists tar ON cs.tarologist_id = tar.id
      WHERE cs.id = ?
    `);
    return stmt.get(id);
  },

  getActiveByUser(userId) {
    const stmt = db.prepare(`
      SELECT * FROM chat_sessions
      WHERE user_id = ? AND active = 1 AND completed = 0
      ORDER BY start_time DESC
      LIMIT 1
    `);
    return stmt.get(userId);
  },

  markCompleted(id) {
    const stmt = db.prepare(`
      UPDATE chat_sessions
      SET active = 0, completed = 1, end_time = CURRENT_TIMESTAMP
      WHERE id = ?
    `);
    return stmt.run(id);
  },

  isExpired(id) {
    const session = this.getById(id);
    if (!session) return true;

    const startTime = new Date(session.start_time).getTime();
    const now = Date.now();
    const elapsed = (now - startTime) / 1000;

    return elapsed >= session.duration_seconds;
  }
};

export const Message = {
  create(data) {
    const stmt = db.prepare(`
      INSERT INTO messages (session_id, sender_id, sender_type, text)
      VALUES (?, ?, ?, ?)
    `);
    const result = stmt.run(data.sessionId, data.senderId, data.senderType, data.text);
    return this.getById(result.lastInsertRowid);
  },

  getById(id) {
    const stmt = db.prepare('SELECT * FROM messages WHERE id = ?');
    return stmt.get(id);
  },

  getBySession(sessionId) {
    const stmt = db.prepare(`
      SELECT * FROM messages
      WHERE session_id = ?
      ORDER BY timestamp ASC
    `);
    return stmt.all(sessionId);
  }
};

// ========================================
// Утилиты
// ========================================

/**
 * Расчёт цены на основе количества завершённых сессий
 * @param {number} sessionsCompleted - количество завершённых сессий
 * @returns {number} цена в звёздах
 */
export function calculatePrice(sessionsCompleted) {
  const level = Math.floor(sessionsCompleted / 10) + 1;
  const price = 33 * Math.pow(1.1, level - 1);
  return Math.min(Math.round(price), 333);
}

/**
 * Инициализация тестовыми данными
 */
export function initializeTestData() {
  const count = db.prepare('SELECT COUNT(*) as count FROM tarologists').get().count;

  if (count === 0) {
    console.log('Инициализация тестовых данных...');

    Tarologist.create({
      name: 'Александра',
      photo_url: 'https://via.placeholder.com/200x200/8B5CF6/FFFFFF?text=A',
      description: 'Профессиональный таролог с 5-летним опытом. Специализируюсь на отношениях и карьере.',
      telegram_id: 'tarologist_1'
    });

    Tarologist.create({
      name: 'Михаил',
      photo_url: 'https://via.placeholder.com/200x200/6366F1/FFFFFF?text=M',
      description: 'Эксперт по картам Таро и астрологии. Помогу найти верный путь в сложной ситуации.',
      telegram_id: 'tarologist_2'
    });

    Tarologist.create({
      name: 'Елена',
      photo_url: 'https://via.placeholder.com/200x200/EC4899/FFFFFF?text=E',
      description: 'Потомственная гадалка. Работаю с Таро более 10 лет. Расклады на любую тематику.',
      telegram_id: 'tarologist_3'
    });

    console.log('Тестовые данные созданы');
  }
}

export default db;

/**
 * Tarot Mini App Server
 * Сервер для интеграции Telegram Stars и чата с тарологами
 */

import express from 'express';
import { createServer } from 'http';
import { Server } from 'socket.io';
import cors from 'cors';
import axios from 'axios';
import crypto from 'crypto';
import dotenv from 'dotenv';

import db, {
  Tarologist,
  User,
  Transaction,
  ChatSession,
  Message,
  calculatePrice,
  initializeTestData
} from './db.js';

dotenv.config();

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer, {
  cors: {
    origin: process.env.CLIENT_URL || '*',
    methods: ['GET', 'POST']
  }
});

const PORT = process.env.PORT || 3001;
const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
const WEBHOOK_URL = process.env.TELEGRAM_WEBHOOK_URL;

// ========================================
// Middleware
// ========================================

app.use(cors({
  origin: process.env.CLIENT_URL || '*',
  credentials: true
}));
app.use(express.json());

// Логгирование запросов
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

// ========================================
// Утилиты
// ========================================

/**
 * Валидация данных от Telegram
 * @param {Object} initData - данные от Telegram WebApp
 * @returns {boolean}
 */
function validateTelegramData(initData) {
  if (!initData) return false;

  const params = new URLSearchParams(initData);
  const hash = params.get('hash');
  params.delete('hash');

  const dataCheckString = Array.from(params.entries())
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([key, value]) => `${key}=${value}`)
    .join('\n');

  const secretKey = crypto.createHmac('sha256', 'WebAppData')
    .update(BOT_TOKEN)
    .digest();

  const computedHash = crypto.createHmac('sha256', secretKey)
    .update(dataCheckString)
    .digest('hex');

  return computedHash === hash;
}

/**
 * Отправка сообщения через бота
 * @param {string} telegramId - ID пользователя/таролога
 * @param {string} text - текст сообщения
 */
async function sendTelegramMessage(telegramId, text) {
  if (!BOT_TOKEN || !telegramId) return;

  try {
    await axios.post(`https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`, {
      chat_id: telegramId,
      text
    });
  } catch (error) {
    console.error('Ошибка отправки сообщения в Telegram:', error.message);
  }
}

// ========================================
// API Routes
// ========================================

/**
 * GET /api/tarologists
 * Получить список всех тарологов
 */
app.get('/api/tarologists', (req, res) => {
  try {
    const tarologists = Tarologist.getAll();
    res.json({ success: true, data: tarologists });
  } catch (error) {
    console.error('Ошибка получения тарологов:', error);
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

/**
 * GET /api/tarologists/:id
 * Получить таролога по ID
 */
app.get('/api/tarologists/:id', (req, res) => {
  try {
    const tarologist = Tarologist.getById(req.params.id);

    if (!tarologist) {
      return res.status(404).json({ success: false, error: 'Tarologist not found' });
    }

    res.json({ success: true, data: tarologist });
  } catch (error) {
    console.error('Ошибка получения таролога:', error);
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

/**
 * POST /api/user/init
 * Инициализация пользователя (find or create)
 */
app.post('/api/user/init', (req, res) => {
  try {
    const { initData } = req.body;

    if (!validateTelegramData(initData)) {
      return res.status(401).json({ success: false, error: 'Invalid Telegram data' });
    }

    const params = new URLSearchParams(initData);
    const userJson = params.get('user');

    if (!userJson) {
      return res.status(400).json({ success: false, error: 'No user data' });
    }

    const userData = JSON.parse(userJson);
    const user = User.findOrCreate(userData.id.toString(), {
      username: userData.username,
      first_name: userData.first_name,
      last_name: userData.last_name
    });

    res.json({ success: true, data: user });
  } catch (error) {
    console.error('Ошибка инициализации пользователя:', error);
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

/**
 * POST /api/create-invoice
 * Создание инвойса для оплаты
 */
app.post('/api/create-invoice', async (req, res) => {
  try {
    const { tarologistId, userId, initData } = req.body;

    // Валидация Telegram данных
    if (!validateTelegramData(initData)) {
      return res.status(401).json({ success: false, error: 'Invalid Telegram data' });
    }

    const tarologist = Tarologist.getById(tarologistId);
    if (!tarologist) {
      return res.status(404).json({ success: false, error: 'Tarologist not found' });
    }

    const user = User.findOrCreate(
      JSON.parse(new URLSearchParams(initData).get('user')).id.toString(),
      {}
    );

    // Расчёт распределения платежа
    const starsAmount = tarologist.price;
    const developerCut = Math.round(starsAmount * 0.1); // 10%
    const tarologistCut = starsAmount - developerCut; // 90%

    // Создаём транзакцию в БД
    const transaction = Transaction.create({
      userId: user.id,
      tarologistId: tarologist.id,
      amount: starsAmount,
      starsAmount,
      developerCut,
      tarologistCut,
      status: 'pending'
    });

    // Создаём инвойс через Telegram API
    const invoiceData = {
      chat_id: user.telegram_id,
      title: 'Консультация таролога',
      description: `Консультация с тарологом ${tarologist.name} (25 минут)`,
      payload: `tarot_session_${transaction.id}`,
      provider_token: 'STARS',
      currency: 'XTR',
      prices: [
        { label: 'Консультация', amount: starsAmount }
      ],
      start_parameter: `tarot_${transaction.id}`,
      need_name: false,
      need_phone_number: false,
      need_email: false,
      need_shipping_address: false
    };

    const response = await axios.post(
      `https://api.telegram.org/bot${BOT_TOKEN}/sendInvoice`,
      invoiceData
    );

    // Обновляем статус транзакции
    const telegramPaymentId = response.data.result.message_id?.toString();
    Transaction.updateStatus(transaction.id, 'pending', telegramPaymentId);

    res.json({
      success: true,
      data: {
        transactionId: transaction.id,
        invoiceLink: response.data.result.invoice_link,
        starsAmount
      }
    });
  } catch (error) {
    console.error('Ошибка создания инвойса:', error.response?.data || error.message);
    res.status(500).json({
      success: false,
      error: error.response?.data?.description || 'Failed to create invoice'
    });
  }
});

/**
 * POST /api/payment-webhook
 * Вебхук от Telegram о статусе платежа
 */
app.post('/api/payment-webhook', async (req, res) => {
  try {
    const update = req.body;

    // Проверяем, что это успешная оплата
    if (update.pre_checkout_query) {
      // Подтверждаем pre-checkout query
      await axios.post(`https://api.telegram.org/bot${BOT_TOKEN}/answerPreCheckoutQuery`, {
        pre_checkout_query_id: update.pre_checkout_query.id,
        ok: true
      });
      return res.json({ ok: true });
    }

    if (update.message?.successful_payment) {
      const payment = update.message.successful_payment;
      const transactionId = parseInt(payment.invoice_payload.replace('tarot_session_', ''));

      const transaction = Transaction.getById(transactionId);
      if (!transaction) {
        return res.status(404).json({ ok: false, error: 'Transaction not found' });
      }

      // Обновляем статус транзакции
      Transaction.updateStatus(transactionId, 'completed', payment.telegram_payment_charge_id);

      // Создаём сессию чата
      const chatSession = ChatSession.create({
        userId: transaction.user_id,
        tarologistId: transaction.tarologist_id,
        durationSeconds: 1500 // 25 минут
      });

      // Уведомляем таролога
      const tarologist = Tarologist.getById(transaction.tarologist_id);
      if (tarologist?.telegram_id) {
        sendTelegramMessage(
          tarologist.telegram_id,
          `🔮 Новая консультация!\n\nКлиент оплатил сессию.\nСессия ID: ${chatSession.id}\nНачните чат в приложении.`
        );
      }

      console.log(`Платёж успешен. Сессия ${chatSession.id} создана.`);
    }

    res.json({ ok: true });
  } catch (error) {
    console.error('Ошибка обработки вебхука:', error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

/**
 * POST /api/rate
 * Оценка таролога после сессии
 */
app.post('/api/rate', (req, res) => {
  try {
    const { tarologistId, userId, rating, sessionId } = req.body;

    if (!rating || rating < 1 || rating > 5) {
      return res.status(400).json({ success: false, error: 'Invalid rating' });
    }

    // Обновляем рейтинг
    Tarologist.updateRating(tarologistId, rating);

    // Увеличиваем счётчик сессий
    Tarologist.incrementSessions(tarologistId);

    // Завершаем сессию
    if (sessionId) {
      ChatSession.markCompleted(sessionId);
    }

    res.json({ success: true });
  } catch (error) {
    console.error('Ошибка оценки:', error);
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

/**
 * GET /api/session/:id/messages
 * Получить сообщения сессии
 */
app.get('/api/session/:id/messages', (req, res) => {
  try {
    const messages = Message.getBySession(parseInt(req.params.id));
    res.json({ success: true, data: messages });
  } catch (error) {
    console.error('Ошибка получения сообщений:', error);
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

// ========================================
// WebSocket для чата
// ========================================

io.on('connection', (socket) => {
  console.log('Клиент подключился:', socket.id);

  // Подключение к сессии чата
  socket.on('join-session', (data) => {
    const { sessionId, userId, userType } = data; // userType: 'client' | 'tarologist'

    socket.join(`session_${sessionId}`);
    socket.data = { sessionId, userId, userType };

    console.log(`Пользователь ${userId} (${userType}) подключился к сессии ${sessionId}`);

    // Отправляем историю сообщений
    const messages = Message.getBySession(sessionId);
    socket.emit('messages-history', messages);
  });

  // Отправка сообщения
  socket.on('send-message', (data) => {
    const { sessionId, text, senderId, senderType } = data;

    // Проверяем, активна ли сессия
    const session = ChatSession.getById(sessionId);
    if (!session || !session.active) {
      socket.emit('error', { message: 'Сессия не активна' });
      return;
    }

    // Проверяем, не истекло ли время
    if (ChatSession.isExpired(sessionId)) {
      ChatSession.markCompleted(sessionId);
      socket.emit('session-expired');
      return;
    }

    // Сохраняем сообщение
    const message = Message.create({
      sessionId,
      senderId,
      senderType,
      text
    });

    // Рассылаем сообщение всем в сессии
    io.to(`session_${sessionId}`).emit('new-message', {
      id: message.id,
      text: message.text,
      senderId: message.sender_id,
      senderType: message.sender_type,
      timestamp: message.timestamp
    });
  });

  // Запрос оставшегося времени
  socket.on('get-time-left', (sessionId) => {
    const session = ChatSession.getById(sessionId);
    if (!session) {
      socket.emit('time-left', { error: 'Session not found' });
      return;
    }

    const startTime = new Date(session.start_time).getTime();
    const elapsed = (Date.now() - startTime) / 1000;
    const timeLeft = Math.max(0, session.duration_seconds - elapsed);

    socket.emit('time-left', { timeLeft, expired: timeLeft <= 0 });
  });

  socket.on('disconnect', () => {
    console.log('Клиент отключился:', socket.id);
  });
});

// ========================================
// Запуск сервера
// ========================================

// Инициализация тестовых данных
initializeTestData();

// Настройка вебхука Telegram при старте
async function setupWebhook() {
  if (!WEBHOOK_URL || !BOT_TOKEN) {
    console.log('Вебхук не настроен (нет WEBHOOK_URL или BOT_TOKEN)');
    return;
  }

  try {
    await axios.post(`https://api.telegram.org/bot${BOT_TOKEN}/setWebhook`, {
      url: WEBHOOK_URL
    });
    console.log('Вебхук установлен:', WEBHOOK_URL);
  } catch (error) {
    console.error('Ошибка установки вебхука:', error.message);
  }
}

httpServer.listen(PORT, () => {
  console.log(`
╔════════════════════════════════════════════╗
║  🎴 Tarot Mini App Server                 ║
║  Порт: ${PORT}                              ║
║  WebSocket: готов                         ║
╚════════════════════════════════════════════╝
  `);

  setupWebhook();
});

export default app;

